    void setPullDistance(float value){pullDistance=value;setTranslationY(-value);updateFolderPull(value);}
    void animatePullTo(float value,boolean animated){animate().cancel();pullDistance=value;if(!animated||!motionEnabled()){setTranslationY(-value);return;}animate().translationY(-value).setDuration(180).setInterpolator(new android.view.animation.DecelerateInterpolator()).start();}
