    ImageView avatar=new ImageView(this);avatar.setScaleType(ImageView.ScaleType.CENTER_CROP);avatar.setBackground(solidShape(SURFACE,28));avatar.setClipToOutline(true);identity.addView(avatar,new LinearLayout.LayoutParams(dp(56),dp(56)));loadImage(f.avatarUrl,avatar);
