  void refreshSearchUi(int session){if(!searchUiCurrent(session)||status==null||statusRight==null||progress==null)return;String line,right;int percent;boolean running,nameOnly,paused; synchronized(globalSearch){running=globalSearch.running;nameOnly=globalSearch.nameOnly;paused=globalSearch.paused;percent=globalSearch.percent;if(nameOnly)line="名称匹配 "+globalSearch.items.size()+" 个项目";else line=(running?"正在搜索 "+globalSearch.active+"/"+Math.max(1,globalSearch.total)+" 个源 · ":"")+"已完成 "+globalSearch.done+" · 找到 "+globalSearch.items.size()+(globalSearch.source.isEmpty()?"":" · "+globalSearch.source);right=paused?"已暂停":globalSearch.right.isEmpty()?(running?"实时追加":globalSearch.failures==0?"已完成":"已完成 · "+globalSearch.failures+" 源异常"):globalSearch.right;}progress.setVisibility(running?View.VISIBLE:View.GONE);progress.setIndeterminate(running&&!paused&&percent==0);if(paused||percent>0){progress.setIndeterminate(false);progress.setProgress(percent);}status.setText(line);statusRight.setText(right);if(searchPauseButton!=null){searchPauseButton.setVisibility(running&&!nameOnly?View.VISIBLE:View.GONE);searchPauseButton.setText(paused?"继续":"暂停");searchPauseButton.setContentDescription(paused?"继续全源搜索":"暂停全源搜索");}}
  void toggleSearchPaused(int session){synchronized(globalSearch){if(session!=searchGeneration||!globalSearch.running||globalSearch.nameOnly)return;globalSearch.paused=!globalSearch.paused;globalSearch.notifyAll();}refreshSearchUi(session);}
  void acceptSearchBatch(int session,List<Models.Item> batch){if(batch==null||batch.isEmpty()||session!=searchGeneration)return;List<Models.Item> fresh=new ArrayList<>(),updates=new ArrayList<>();synchronized(globalSearch){if(session!=searchGeneration)return;for(Models.Item item:batch){Models.Item present=globalSearch.byUrl.get(item.url);if(present==null){globalSearch.byUrl.put(item.url,item);insertGlobalSearchItem(globalSearch,item);fresh.add(item);}else{mergeSearchItem(present,item);updates.add(present);}}globalSearch.right="已显示 "+globalSearch.items.size();}queueSearchUi(session,fresh,updates);}
