  View bulkDownloadPreview(List<Models.Item> items){LinearLayout holder=new LinearLayout(this);holder.setGravity(Gravity.CENTER);GridLayout preview=new GridLayout(this);preview.setColumnCount(4);preview.setRowCount(2);int slots=Math.min(8,items.size());for(int i=0;i<slots;i++){FrameLayout tile=new FrameLayout(this);GridLayout.LayoutParams cell=new GridLayout.LayoutParams();cell.width=dp(50);cell.height=dp(50);cell.setMargins(dp(4),dp(3),dp(4),dp(3));if(items.size()>8&&i==7){TextView more=text("…",23,PRIMARY);more.setGravity(Gravity.CENTER);more.setBackground(solidShape(SURFACE,11));more.setContentDescription("还有 "+(items.size()-7)+" 个项目");tile.addView(more,new FrameLayout.LayoutParams(-1,-1));TextView badge=text("+"+(items.size()-7),9,BG);badge.setGravity(Gravity.CENTER);badge.setBackground(solidShape(PRIMARY,9));FrameLayout.LayoutParams badgeParams=new FrameLayout.LayoutParams(dp(28),dp(18),Gravity.END|Gravity.TOP);tile.addView(badge,badgeParams);}else{Models.Item item=items.get(i);ImageView icon=new ImageView(this);icon.setScaleType(ImageView.ScaleType.CENTER_CROP);icon.setBackground(solidShape(BG,10));icon.setClipToOutline(true);icon.setImageResource(item.folder?R.drawable.ic_folder:R.drawable.ic_file);icon.setContentDescription(item.title);tile.addView(icon,new FrameLayout.LayoutParams(-1,-1));loadImage(item.iconUrl,icon);}preview.addView(tile,cell);}holder.addView(preview,new LinearLayout.LayoutParams(-2,-1));return holder;}
