  void runSearch(String q){
    if(q.isEmpty())return;homeSearchHistoryOnly=false;homeSearchRequested=true;if(!homeSearchFocused)showHomeSearchMode(false);saveSearchHistory(q);if(search!=null){if(!q.equals(search.getText().toString())){search.setText(q);search.setSelection(q.length());}search.clearFocus();((android.view.inputmethod.InputMethodManager)getSystemService(INPUT_METHOD_SERVICE)).hideSoftInputFromWindow(search.getWindowToken(),0);}if(selectionMode)exitSelection();clearFolderTrail();folderRootSources=false;activeSource=home;systemBackAction=this::exitHomeSearchFocus;final int session=++searchGeneration,points=q.codePointCount(0,q.length());final String category=sessionSearchCategory;final boolean apiOnly=sessionSearchApiOnly;final Set<String> sourceNameScope=searchCategoryIds(category);final List<Models.Item> homeSnapshot=new ArrayList<>(homeItems);synchronized(globalSearch){globalSearch.query=q;globalSearch.source="";globalSearch.right=points<2?"仅名称匹配":"实时追加";globalSearch.active=0;globalSearch.done=0;globalSearch.total=0;globalSearch.pages=0;globalSearch.percent=0;globalSearch.failures=0;globalSearch.folderCount=0;globalSearch.running=points>=2;globalSearch.nameOnly=points<2;globalSearch.paused=false;globalSearch.items.clear();globalSearch.byUrl.clear();globalSearch.notifyAll();}renderSearchResults();
    io.execute(()->{try{
      Set<String> allowedSources=searchAllowedSourceIds(category,apiOnly);int sourceTotal=points<2?0:searchableSourceTotal(allowedSources);synchronized(globalSearch){if(session!=searchGeneration)return;globalSearch.total=sourceTotal;}queueSearchRefresh(session);List<Models.Item> sourceNames=core.sourceNameItems(q,sourceNameScope);acceptSearchBatch(session,sourceNames);List<Models.Item> homeLocal=allowedSources==null||allowedSources.contains(sourceKey(home))?homeSnapshot:new ArrayList<>();String homeId=sourceKey(home);for(Models.Item item:homeLocal){if(item.source.isEmpty())item.source=home.title;if(item.sourceId.isEmpty())item.sourceId=homeId;}if(points<2){try{homeLocal.addAll(core.localSourceItems(allowedSources));}catch(Exception ignored){}String key=q.toLowerCase(Locale.ROOT);List<Models.Item> matches=new ArrayList<>();for(Models.Item item:homeLocal)if(item.title.toLowerCase(Locale.ROOT).contains(key))matches.add(item);acceptSearchBatch(session,matches);queueSearchRefresh(session);return;}
      List<Models.Item> result=core.search(q,home,homeLocal,searchOptions(sourceTotal),allowedSources,new Models.Progress(){
        @Override public boolean isCancelled(){return session!=searchGeneration;}
        @Override public boolean awaitIfPaused(){synchronized(globalSearch){while(session==searchGeneration&&globalSearch.paused)try{globalSearch.wait();}catch(InterruptedException interrupted){Thread.currentThread().interrupt();return false;}return session==searchGeneration;}}
        @Override public void onBatch(List<Models.Item> batch){acceptSearchBatch(session,batch);}
        @Override public void onItemUpdated(Models.Item item){acceptSearchItemUpdate(session,item);}
        @Override public void onActivity(int active,int total,String source){synchronized(globalSearch){if(session!=searchGeneration)return;globalSearch.active=active;globalSearch.total=total;if(source!=null&&!source.isEmpty())globalSearch.source=source;}queueSearchRefresh(session);}
        @Override public void onFailure(String source){synchronized(globalSearch){if(session==searchGeneration)globalSearch.failures++;}}
        @Override public void onPage(String source,int page,int pageItems,int sourceFound,int totalPagesSeen){synchronized(globalSearch){if(session!=searchGeneration)return;globalSearch.source=source;globalSearch.pages=totalPagesSeen;globalSearch.right="第 "+page+" 页 · 累计 "+totalPagesSeen+" 页";}queueSearchRefresh(session);}
        @Override public void onProgress(int done,int total,int found,String source){synchronized(globalSearch){if(session!=searchGeneration)return;globalSearch.done=done;globalSearch.total=total;globalSearch.source=source;globalSearch.percent=done*100/Math.max(1,total);globalSearch.right="已显示 "+globalSearch.items.size();}queueSearchRefresh(session);}
      });
      acceptSearchBatch(session,result);finishSearchJob(session);
    }catch(Exception e){if(session==searchGeneration){synchronized(globalSearch){globalSearch.failures++;}finishSearchJob(session);showNotice(friendlyError(e),true);}}});
  }
  void finishSearchJob(int session){synchronized(globalSearch){if(session!=searchGeneration)return;globalSearch.active=0;globalSearch.running=false;globalSearch.paused=false;globalSearch.percent=100;globalSearch.right=globalSearch.failures==0?"已完成":"已完成 · "+globalSearch.failures+" 源异常";globalSearch.notifyAll();}queueSearchRefresh(session);}
  void openSearchSourcePage(Models.Source source){pageDirection=1;resetFolderTrail(source);folderRootSources=false;showFolderPage(activeFolderState.source,true);}
  void openSourceSearchResult(Models.Item item){try{Models.Source source=core.sourceById(item.sourceId);if(source==null){if(item.folder)openNestedFolder(item);else confirmDownload(item);return;}if(singleFileSource(source))confirmDownload(singleFileItem(source));else openSearchSourcePage(source);}catch(Exception error){showNotice("无法打开软件源："+friendlyError(error),true);}}
  TextView sourceTag(String value){TextView tag=text(value,10,PRIMARY);tag.setGravity(Gravity.CENTER);tag.setPadding(dp(7),0,dp(7),0);tag.setBackground(shape(Color.argb(darkMode?64:24,Color.red(PRIMARY),Color.green(PRIMARY),Color.blue(PRIMARY)),8));return tag;}
  List<String> sourceCategoryMemberships(Models.Source source){List<String> out=new ArrayList<>();if(!"全部".equals(activeSourceCategory))return out;String id=sourceKey(source),stable=LanzouCore.sourceId(source);for(Map.Entry<String,LinkedHashSet<String>> entry:sourceCategories.entrySet())if(entry.getValue().contains(id)||entry.getValue().contains(stable))out.add(entry.getKey());return out;}
  String sourceSearchCorpus(Models.Source source){StringBuilder out=new StringBuilder(source.title).append(' ').append(source.url).append(' ').append(source.password).append(' ').append(source.publisher).append(' ').append(source.description);for(Models.SourceMember member:source.members)out.append(' ').append(member.title).append(' ').append(member.url).append(' ').append(member.password).append(' ').append(member.description);return out.toString();}
  static String sourceInputLine(String url,String password){String link=url==null?"":url.trim(),pwd=password==null?"":password.trim();return link.isEmpty()?"":link+(pwd.isEmpty()?"":" "+pwd);}
  void appendSourceInputLines(LinkedHashSet<String> lines,Models.Source source){if(!compositeSource(source)||transientLinkSource(source)){String line=sourceInputLine(source.url,source.password);if(!line.isEmpty())lines.add(line);return;}for(Models.SourceMember member:source.members){String line=sourceInputLine(member.url,member.password);if(!line.isEmpty())lines.add(line);}}
  String sourceShareText(Models.Source source){LinkedHashSet<String> lines=new LinkedHashSet<>();appendSourceInputLines(lines,source);return String.join("\n",lines);}
