  View sourceDestinationRow(SourceDestination destination,Map<String,SourceDestination> selected,Runnable enter,Runnable changed){LinearLayout row=new LinearLayout(this);row.setGravity(Gravity.CENTER_VERTICAL);row.setPadding(dp(4),0,dp(4),0);row.setBackground(filterRipple(new ColorDrawable(Color.TRANSPARENT)));CheckBox pick=new CheckBox(this);pick.setChecked(selected.containsKey(destination.key()));pick.setContentDescription("选择路径 "+destination.path);pick.setOnCheckedChangeListener((button,checked)->{if(checked)selected.put(destination.key(),destination);else selected.remove(destination.key());changed.run();});row.addView(pick,new LinearLayout.LayoutParams(dp(44),dp(48)));ImageView folder=new ImageView(this);folder.setImageResource(R.drawable.ic_folder);folder.setColorFilter(PRIMARY);folder.setImportantForAccessibility(View.IMPORTANT_FOR_ACCESSIBILITY_NO);row.addView(folder,new LinearLayout.LayoutParams(dp(24),dp(24)));TextView name=text(destination.path.substring(destination.path.lastIndexOf('›')+1).trim(),13,TEXT);name.setSingleLine(true);name.setEllipsize(android.text.TextUtils.TruncateAt.END);name.setPadding(dp(10),0,dp(6),0);row.addView(name,new LinearLayout.LayoutParams(0,dp(48),1));ImageButton open=iconButton(R.drawable.ic_expand,"进入 "+name.getText());open.setRotation(-90f);open.setOnClickListener(v->enter.run());row.addView(open,new LinearLayout.LayoutParams(dp(42),dp(48)));name.setClickable(true);name.setOnClickListener(v->enter.run());row.setContentDescription("路径 "+destination.path+"，可勾选或进入");return row;}
  void showSourceDestinationPicker(List<Models.Source> sourceInput,List<Models.Item> itemInput){
    loadSourceCategories();
    List<Models.Source> available;
    try{available=core.sources();}catch(Exception error){showNotice("无法读取分类目录",true);return;}
    List<Models.Source> sources=new ArrayList<>(sourceInput==null?Collections.emptyList():sourceInput);
    List<Models.Item> items=new ArrayList<>(itemInput==null?Collections.emptyList():itemInput);
    LinkedHashMap<String,SourceDestination> selected=new LinkedHashMap<>();
    ArrayList<SourceDestination> stack=new ArrayList<>();
    SourceDestination[] current={null};
    LinearLayout panel=new LinearLayout(this);panel.setOrientation(LinearLayout.VERTICAL);panel.setPadding(dp(10),dp(4),dp(10),0);
    LinearLayout locationBar=new LinearLayout(this);locationBar.setGravity(Gravity.CENTER_VERTICAL);
    ImageButton back=iconButton(R.drawable.ic_back,"返回上一级");
    TextView path=text("当前路径：分类",13,TEXT);path.setSingleLine(true);path.setEllipsize(android.text.TextUtils.TruncateAt.START);
    locationBar.addView(back,new LinearLayout.LayoutParams(dp(44),dp(44)));locationBar.addView(path,new LinearLayout.LayoutParams(0,dp(44),1));panel.addView(locationBar,new LinearLayout.LayoutParams(-1,dp(44)));
    TextView summary=text("已选 0 个路径",12,PRIMARY);summary.setGravity(Gravity.START|Gravity.CENTER_VERTICAL);panel.addView(summary,new LinearLayout.LayoutParams(-1,dp(34)));
    LinearLayout choices=new LinearLayout(this);choices.setOrientation(LinearLayout.VERTICAL);
    ScrollView scroll=new ScrollView(this);scroll.setFillViewport(false);scroll.setVerticalScrollBarEnabled(true);scroll.addView(choices,new ScrollView.LayoutParams(-1,-2));
    panel.addView(scroll,new LinearLayout.LayoutParams(-1,Math.min(dp(330),Math.max(dp(180),getResources().getDisplayMetrics().heightPixels-dp(350)))));
    AlertDialog prompt=new AlertDialog.Builder(this).setTitle("批量选择加入路径").setView(panel).setNegativeButton("取消",null).setPositiveButton("添加到所选路径",null).create();
    Button[] submit={null};Runnable[] update={null},render={null};
    update[0]=()->{summary.setText("已选 "+selected.size()+" 个路径");summary.setContentDescription("提交前摘要，已选 "+selected.size()+" 个路径");if(submit[0]!=null)submit[0].setEnabled(!selected.isEmpty());};
    render[0]=()->{
      choices.removeAllViews();SourceDestination here=current[0];path.setText("当前路径："+(here==null?"分类":here.path));back.setEnabled(here!=null);
      LinkedHashMap<String,SourceDestination> level=new LinkedHashMap<>();
      if(here==null){
        level.putIfAbsent("全部",new SourceDestination("全部",null,"","全部"));
        for(String category:sourceCategories.keySet()){String dedupe=category.toLowerCase(Locale.ROOT);level.putIfAbsent(dedupe,new SourceDestination(category,null,"",category));}
      }else if(here.categoryOnly()){
        Set<String> ids=here.category.equals("全部")?null:sourceCategories.get(here.category);
        for(Models.Source source:available)if(compositeSource(source)&&(ids==null||ids.contains(sourceKey(source)))){
          String title=source.title.isEmpty()?"自建目录":source.title;
          SourceDestination destination=new SourceDestination(here.category,source,"",here.category+" › "+title);
          level.putIfAbsent(destination.key(),destination);
        }
      }else{
        for(Models.SourceMember member:here.composite.members)if(member.kind==Models.MEMBER_FOLDER&&member.parentId.equals(here.nodeId)&&!member.title.isEmpty()){
          SourceDestination destination=new SourceDestination(here.category,here.composite,member.id,here.path+" › "+member.title);
          level.putIfAbsent(destination.key(),destination);
        }
      }
      for(SourceDestination destination:level.values()){
        Runnable enter=()->{stack.add(current[0]);current[0]=destination;render[0].run();};
        choices.addView(sourceDestinationRow(destination,selected,enter,update[0]),new LinearLayout.LayoutParams(-1,dp(50)));
      }
      if(level.isEmpty()){TextView empty=text("此位置没有下级自建目录",12,MUTED);empty.setGravity(Gravity.CENTER);choices.addView(empty,new LinearLayout.LayoutParams(-1,dp(72)));}
      scroll.scrollTo(0,0);update[0].run();
    };
    back.setOnClickListener(v->{if(current[0]==null)return;current[0]=stack.isEmpty()?null:stack.remove(stack.size()-1);render[0].run();});
    prompt.setOnShowListener(ignored->{submit[0]=prompt.getButton(AlertDialog.BUTTON_POSITIVE);submit[0].setOnClickListener(v->{if(selected.isEmpty())return;List<SourceDestination> destinations=new ArrayList<>(selected.values());prompt.dismiss();applySelectedDestinations(sources,items,destinations);});render[0].run();});
    showRounded(prompt);
  }
  void applySelectedDestinations(List<Models.Source> rawSources,List<Models.Item> rawItems,List<SourceDestination> destinations){if(destinations==null||destinations.isEmpty())return;showNotice("正在加入 "+destinations.size()+" 个路径",false);List<Models.Source> sources=new ArrayList<>(rawSources==null?Collections.emptyList():rawSources);List<Models.Item> items=new ArrayList<>(rawItems==null?Collections.emptyList():rawItems);io.execute(()->{LinkedHashMap<String,String[]> links=new LinkedHashMap<>();LinkedHashSet<String> sourceIds=new LinkedHashSet<>();boolean categoryTarget=false;for(SourceDestination destination:destinations)categoryTarget|=destination.categoryOnly();int addedDirectories=0,duplicates=0,failed=0;try{List<Models.Source> known=core.sources();LinkedHashMap<String,Models.Source> knownById=new LinkedHashMap<>(),knownByUrl=new LinkedHashMap<>();for(Models.Source source:known){knownById.put(sourceKey(source),source);if(!source.url.isEmpty())knownByUrl.put(source.url,source);}for(Models.Source source:sources){String requestedId=source.kind==Models.SOURCE_COMPOSITE&&!source.id.isEmpty()?source.id:sourceKey(source);Models.Source knownSource=knownById.get(requestedId);if(knownSource!=null)sourceIds.add(sourceKey(knownSource));else if(categoryTarget&&!source.url.isEmpty())try{Models.Source stored=core.addUserSource(source.url,source.password);sourceIds.add(sourceKey(stored));knownById.put(sourceKey(stored),stored);knownByUrl.put(stored.url,stored);}catch(Exception error){failed++;}if(!source.url.isEmpty())links.putIfAbsent(source.url+'\n'+source.password,new String[]{source.url,source.password});}for(Models.Item item:items){if(item.sourceEntry)try{Models.Source source=core.sourceById(item.sourceId);if(source!=null){sourceIds.add(sourceKey(source));if(!source.url.isEmpty())links.putIfAbsent(source.url+'\n'+source.password,new String[]{source.url,source.password});continue;}}catch(Exception ignored){}String url=item.shareUrl.isEmpty()?item.url:item.shareUrl;if(url.isEmpty()||!url.toLowerCase(Locale.ROOT).startsWith("http"))continue;links.putIfAbsent(url+'\n'+item.password,new String[]{url,item.password});if(categoryTarget){Models.Source knownSource=knownByUrl.get(url);if(knownSource!=null)sourceIds.add(sourceKey(knownSource));else try{Models.Source stored=core.addUserSource(url,item.password);sourceIds.add(sourceKey(stored));knownByUrl.put(stored.url,stored);}catch(Exception error){failed++;}}}for(SourceDestination destination:destinations)if(!destination.categoryOnly())for(String[] link:links.values())try{core.addCompositeNode(destination.composite.id,destination.nodeId,link[0],link[1]);addedDirectories++;}catch(Exception error){String message=error.getMessage()==null?"":error.getMessage();if(message.contains("已在当前文件夹"))duplicates++;else failed++;}List<Models.Source> updated=core.sources();int directoryCount=addedDirectories,duplicateCount=duplicates,failureCount=failed;runOnUiThread(()->{int categoryAdds=0;for(SourceDestination destination:destinations)if(destination.categoryOnly()){Set<String> category=sourceCategories.get(destination.category);if(category==null)continue;int before=category.size();category.addAll(sourceIds);categoryAdds+=category.size()-before;}if(categoryAdds>0)persistSourceCategories();++sourceDataRevision;if(selectionMode)exitSelection();if(sourceSelectionMode)exitSourceSelection();if(sourcePageSources!=null){sourcePageSources.clear();sourcePageSources.addAll(updated);if(sourceGrid!=null&&sourceHeading!=null){renderSourceCategories(sourcePageSources);renderSources(sourceGrid,sourcePageSources,sourceFilter==null?"":sourceFilter.getText().toString().trim(),sourceHeading);}}showNotice("已处理 "+destinations.size()+" 个路径 · 分类新增 "+categoryAdds+" · 目录新增 "+directoryCount+(duplicateCount>0?" · 重复 "+duplicateCount:"")+(failureCount>0?" · 失败 "+failureCount:""),failureCount>0);});}catch(Exception error){showNotice("批量加入失败："+friendlyError(error),true);}});}
  void addCurrentSourceToCategory(Models.Source source,String categoryName){showNotice("正在加入“"+categoryName+"”",false);io.execute(()->{try{String id=source.kind==Models.SOURCE_COMPOSITE&&!source.id.isEmpty()?source.id:sourceKey(source);boolean present=false;for(Models.Source candidate:core.sources())if(sourceKey(candidate).equals(id)){present=true;break;}if(!present){Models.Source stored=core.addUserSource(source.url,source.password);id=sourceKey(stored);}String sourceId=id;runOnUiThread(()->{LinkedHashSet<String> category=sourceCategories.get(categoryName);if(category==null){showNotice("分类已不存在",true);return;}boolean added=category.add(sourceId);if(added){persistSourceCategories();++sourceDataRevision;}showNotice(added?"已加入“"+categoryName+"”":"当前源已在“"+categoryName+"”",false);});}catch(Exception error){runOnUiThread(()->showNotice("加入分类失败："+friendlyError(error),true));}});}
  String sourceCategoryTagKey(Models.Source source){return "source-category-tags:"+sourceKey(source);}
  void replaceSourceCategoryTags(HorizontalScrollView scroll,Models.Source source){List<String> memberships=sourceCategoryMemberships(source);scroll.removeAllViews();LinearLayout tags=new LinearLayout(this);tags.setGravity(Gravity.START|Gravity.CENTER_VERTICAL);for(String membership:memberships){LinearLayout.LayoutParams p=new LinearLayout.LayoutParams(-2,dp(22));p.setMargins(0,0,dp(4),0);tags.addView(sourceTag(membership),p);}scroll.addView(tags,new HorizontalScrollView.LayoutParams(-2,dp(22)));scroll.setVisibility(memberships.isEmpty()?View.GONE:View.VISIBLE);}
  void refreshSourcesAfterCategoryChange(Collection<Models.Source> changed){if(changed==null||changed.isEmpty()||sourceGrid==null||sourceGrid.getParent()==null)return;int scrollY=pageScroll==null?0:pageScroll.getScrollY();for(Models.Source source:changed){View tagged=sourceGrid.findViewWithTag(sourceCategoryTagKey(source));if(!(tagged instanceof HorizontalScrollView))continue;HorizontalScrollView tags=(HorizontalScrollView)tagged;Runnable replace=()->{replaceSourceCategoryTags(tags,source);if(tags.getVisibility()==View.VISIBLE&&motionEnabled()){tags.setAlpha(0f);tags.animate().alpha(1f).setDuration(120).start();}else tags.setAlpha(1f);};tags.animate().cancel();if(motionEnabled()&&tags.getVisibility()==View.VISIBLE)tags.animate().alpha(0f).setDuration(80).withEndAction(replace).start();else replace.run();}if(pageScroll!=null)pageScroll.post(()->{if(pageKind==1&&pageScroll!=null)pageScroll.scrollTo(0,scrollY);});}
  void renameSelectedCompositeSource(){List<Models.Source> chosen=selectedSources();if(chosen.size()!=1||!compositeSource(chosen.get(0)))return;Models.Source source=chosen.get(0);EditText name=sourceInput("合集名称",android.text.InputType.TYPE_CLASS_TEXT|android.text.InputType.TYPE_TEXT_FLAG_CAP_SENTENCES);name.setText(source.title);name.setSelection(name.length());LinearLayout panel=new LinearLayout(this);panel.setPadding(dp(22),dp(8),dp(22),0);panel.addView(name,new LinearLayout.LayoutParams(-1,dp(56)));AlertDialog prompt=new AlertDialog.Builder(this).setTitle("重命名自建合集").setView(panel).setNegativeButton("取消",null).setPositiveButton("保存",null).create();prompt.setOnShowListener(ignored->{Button save=prompt.getButton(AlertDialog.BUTTON_POSITIVE);save.setOnClickListener(v->{String title=name.getText().toString().trim();if(title.isEmpty()){name.setError("请输入合集名称");return;}save.setEnabled(false);io.execute(()->{try{Models.Source updated=core.updateCompositeMetadata(sourceKey(source),title,source.publisher,source.description);runOnUiThread(()->{copySource(updated,source);prompt.dismiss();exitSourceSelection();renderSources(sourceGrid,sourcePageSources,sourceFilter==null?"":sourceFilter.getText().toString().trim(),sourceHeading);showNotice("已重命名为“"+title+"”",false);});}catch(Exception error){runOnUiThread(()->{save.setEnabled(true);name.setError(friendlyError(error));});}});});});showRounded(prompt);}
  void renderSources(GridLayout grid,List<Models.Source> all,String query,TextView heading){
    int token=++sourceRenderSession;grid.removeAllViews();sourceSelectionChecks.clear();visibleSources.clear();int columns=itemColumns();grid.setColumnCount(columns);String key=query.toLowerCase(Locale.ROOT);Set<String> category=sourceCategories.get(activeSourceCategory);if(!activeSourceCategory.equals("全部")&&category==null)activeSourceCategory="全部";for(Models.Source source:all)if((activeSourceCategory.equals("全部")||category.contains(sourceKey(source)))&&(key.isEmpty()||sourceSearchCorpus(source).toLowerCase(Locale.ROOT).contains(key)))visibleSources.add(source);heading.setText("源列表 · "+activeSourceCategory+" · "+visibleSources.size()+(key.isEmpty()?"":"/"+all.size()));renderSourceChunk(grid,new ArrayList<>(visibleSources),0,columns,token);if(sourceSelectionMode)updateSourceSelectionSummary();
  }
