  void loadSourceCategories(){sourceCategories.clear();boolean migrated=false;List<Models.Source> known=Collections.emptyList();try{known=core.sources();}catch(Exception ignored){}try{org.json.JSONArray groups=new org.json.JSONArray(getSharedPreferences("source_categories",MODE_PRIVATE).getString("items","[]"));for(int i=0;i<groups.length();i++){org.json.JSONObject group=groups.optJSONObject(i);if(group==null)continue;String name=group.optString("name").trim();if(name.isEmpty()||name.equals("全部")||sourceCategories.containsKey(name))continue;LinkedHashSet<String> ids=new LinkedHashSet<>();org.json.JSONArray values=group.optJSONArray("ids");if(values==null){values=group.optJSONArray("urls");migrated|=values!=null;}if(values!=null)for(int j=0;j<values.length();j++){String stored=values.optString(j);if(stored.isEmpty())continue;String resolved=stored;for(Models.Source source:known)if(stored.equals(source.id)||stored.equals(source.url)){resolved=sourceKey(source);break;}if(!resolved.isEmpty())ids.add(resolved);}sourceCategories.put(name,ids);}}catch(Exception ignored){}if(migrated)persistSourceCategories();if(!activeSourceCategory.equals("全部")&&!sourceCategories.containsKey(activeSourceCategory))activeSourceCategory="全部";}
