  void enterSourceSelection(){if(sourceSelectionMode)return;sourceSelectionMode=true;sourceSelectionSummary=text("已选 0",11,TEXT);sourceSelectionAllButton=toolbarTextButton("全选");sourceSelectionAllButton.setOnClickListener(v->toggleSelectAllSources());ImageButton copy=iconButton(R.drawable.ic_copy,"复制所选源链接"),share=iconButton(R.drawable.ic_share,"分享所选源链接"),save=iconButton(R.drawable.ic_download,"保存所选源到蓝奏云优享版"),categorize=iconButton(R.drawable.ic_add,"加入分类"),retest=iconButton(R.drawable.ic_search,"重新测试所选源"),remove=iconButton(R.drawable.ic_delete_record,"移出当前分类"),close=iconButton(R.drawable.ic_close,"退出源多选");sourceSelectionRename=iconButton(R.drawable.ic_edit,"重命名自建合集");sourceSelectionRename.setVisibility(View.GONE);copy.setOnClickListener(v->copySelectedSources());share.setOnClickListener(v->shareSelectedSources());save.setOnClickListener(v->confirmSaveSelectedSources());categorize.setOnClickListener(v->chooseSourceCategory());sourceSelectionRename.setOnClickListener(v->renameSelectedCompositeSource());retest.setOnClickListener(v->confirmRetestSelectedSources());remove.setOnClickListener(v->confirmRemoveSelectedSources());close.setOnClickListener(v->exitSourceSelection());sourceSelectionBar=makeSelectionBar(sourceSelectionSummary,sourceSelectionAllButton,62,32,copy,share,save,categorize,sourceSelectionRename,retest,remove,close);showChecks(sourceSelectionChecks,true);updateSourceSelectionSummary();}
