  void bindDownloadActions(DownloadEntry entry,LinearLayout actions){actions.removeAllViews();if(entry.state.equals(DOWNLOAD_COMPLETED)){ImageButton deleteFile=iconButton(R.drawable.ic_delete_file,"删除本地文件并同步删除下载记录"),deleteRecord=iconButton(R.drawable.ic_delete_record,"仅删除下载记录并保留本地文件");deleteFile.setOnClickListener(v->confirmDeleteFile(entry));deleteRecord.setOnClickListener(v->removeDownloadRecord(entry));actions.addView(deleteFile,new LinearLayout.LayoutParams(dp(38),dp(42)));actions.addView(deleteRecord,new LinearLayout.LayoutParams(dp(38),dp(42)));return;}if(isDownloadActive(entry)||entry.state.equals(DOWNLOAD_PAUSED)){ImageButton control=iconButton(entry.state.equals(DOWNLOAD_PAUSED)?R.drawable.ic_play:R.drawable.ic_pause,(entry.state.equals(DOWNLOAD_PAUSED)?"继续下载 ":"暂停下载 ")+entry.name);control.setOnClickListener(v->{if(entry.state.equals(DOWNLOAD_PAUSED))resumeDownload(entry);else pauseDownload(entry);});ImageButton cancel=iconButton(R.drawable.ic_close,"取消下载 "+entry.name);cancel.setOnClickListener(v->cancelDownload(entry));actions.addView(control,new LinearLayout.LayoutParams(dp(38),dp(42)));actions.addView(cancel,new LinearLayout.LayoutParams(dp(38),dp(42)));}}
  void bindDownloadRowDescription(DownloadEntry entry,View row){boolean retryable=entry.state.equals(DOWNLOAD_FAILED)||entry.state.equals(DOWNLOAD_CANCELLED);row.setContentDescription(retryable?"下载未完成，点击重新下载 "+entry.name:entry.state.equals(DOWNLOAD_PAUSED)?"已暂停，点击继续 "+entry.name:entry.name+"，"+entry.state+"，长按可多选");}
  String formatSpeed(long bytesPerSecond){return bytesPerSecond<=0?"测速中":formatSize(bytesPerSecond)+"/s";}
  String formatEta(long seconds){if(seconds<0)return"剩余时间计算中";if(seconds<60)return"剩余 "+seconds+" 秒";if(seconds<3600)return"剩余 "+(seconds/60)+" 分 "+(seconds%60)+" 秒";return"剩余 "+(seconds/3600)+" 小时 "+((seconds%3600)/60)+" 分";}
  String downloadMoment(long time){return time<=0?"时间未知":android.text.format.DateFormat.format("yyyy-MM-dd HH:mm",time).toString();}
  String downloadMetrics(DownloadEntry entry){String done=formatSize(entry.downloadedBytes),total=entry.totalBytes>0?formatSize(entry.totalBytes):(entry.sourceSizeText.isEmpty()?"大小未知":entry.sourceSizeText),size=done+" / "+total;if(entry.state.equals(DOWNLOAD_RUNNING))return"下载中 · "+entry.percent+"% · "+size+"\n"+formatSpeed(entry.speedBps)+" · "+formatEta(entry.etaSeconds);if(entry.state.equals(DOWNLOAD_PAUSED))return"已暂停 · "+entry.percent+"% · "+size+"\n再次点击继续";if(entry.state.equals(DOWNLOAD_COMPLETED))return"下载完成 · "+size+"\n完成 "+downloadMoment(entry.completedAt);if(entry.state.equals(DOWNLOAD_FAILED)||entry.state.equals(DOWNLOAD_CANCELLED))return(entry.state.equals(DOWNLOAD_CANCELLED)?"已取消":"下载失败")+(entry.error.isEmpty()?"":" · "+entry.error)+" · "+size+"\n创建 "+downloadMoment(entry.createdAt);if(entry.state.equals(DOWNLOAD_RESOLVING))return"解析中 · "+total+"\n创建 "+downloadMoment(entry.createdAt);return entry.state+" · "+size+"\n创建 "+downloadMoment(entry.createdAt);}
  int downloadTransferParallelism(){int value=getSharedPreferences("download_settings-v1",MODE_PRIVATE).getInt("parallel_transfers",DEFAULT_TRANSFER_PARALLELISM);return value<0||value>128?DEFAULT_TRANSFER_PARALLELISM:value;}
  void setDownloadTransferParallelism(int value){getSharedPreferences("download_settings-v1",MODE_PRIVATE).edit().putInt("parallel_transfers",value<0||value>128?DEFAULT_TRANSFER_PARALLELISM:value).apply();}
  LinearLayout buildDownloadSettingsPanel(){
    int current=directResolver.configuredParallelism(),progress=current==0?128:current-1,transfers=downloadTransferParallelism(),transferProgress=transfers==0?128:transfers-1;LinearLayout panel=new LinearLayout(this);panel.setOrientation(LinearLayout.VERTICAL);panel.setPadding(0,dp(2),0,dp(12));TextView label=text(current==0?"解析并发：无限":"解析并发："+current,14,TEXT);SeekBar bar=new SeekBar(this);bar.setMax(128);bar.setProgress(progress);bar.setContentDescription("调整直链解析并发，最右为无限");bar.setOnSeekBarChangeListener(new android.widget.SeekBar.OnSeekBarChangeListener(){public void onProgressChanged(SeekBar value,int position,boolean user){label.setText(position==128?"解析并发：无限":"解析并发："+(position+1));if(user)directResolver.setParallelism(position==128?0:position+1);}public void onStartTrackingTouch(SeekBar value){}public void onStopTrackingTouch(SeekBar value){}});panel.addView(label,new LinearLayout.LayoutParams(-1,dp(42)));panel.addView(bar,new LinearLayout.LayoutParams(-1,dp(48)));TextView transferLabel=text(transfers==0?"同时下载：无限":"同时下载："+transfers,14,TEXT);SeekBar transferBar=new SeekBar(this);transferBar.setMax(128);transferBar.setProgress(transferProgress);transferBar.setContentDescription("调整批量任务同时下载数，最右为无限");transferBar.setOnSeekBarChangeListener(new android.widget.SeekBar.OnSeekBarChangeListener(){public void onProgressChanged(SeekBar value,int position,boolean user){transferLabel.setText(position==128?"同时下载：无限":"同时下载："+(position+1));if(user)setDownloadTransferParallelism(position==128?0:position+1);}public void onStartTrackingTouch(SeekBar value){}public void onStopTrackingTouch(SeekBar value){}});panel.addView(transferLabel,new LinearLayout.LayoutParams(-1,dp(42)));panel.addView(transferBar,new LinearLayout.LayoutParams(-1,dp(48)));return panel;
  }
