  LinearLayout buildPrivacyPolicyPanel(){LinearLayout panel=new LinearLayout(this);panel.setOrientation(LinearLayout.VERTICAL);panel.setPadding(dp(6),0,dp(6),dp(12));String policy="本软件不会建立自有云端账号系统。源规则、搜索记录、下载记录与保存路径等设置保存在本机。\n\n使用蓝奏云优享版登录时，账号、密码和会话仅提交至蓝奏云优享版官方接口；本机凭据由 Android KeyStore 加密保存。\n\n搜索、解析、图标读取、更新检查与下载会访问对应蓝奏云分享地址、软件官网或开源发布服务。下载文件仅保存在系统 Download 或用户所选目录。\n\n软件仅在安装、目录访问、后台下载等对应功能时申请 Android 权限；拒绝权限不会上传本机文件。";TextView content=text(policy,13,TEXT);content.setGravity(Gravity.START);content.setTextIsSelectable(true);content.setLineSpacing(dp(3),1f);selectableLinks(content);panel.addView(content,new LinearLayout.LayoutParams(-1,-2));return panel;}
