  TextView premiumAccountLabel(String account){String masked=PremiumCloudClient.maskAccount(account);TextView label=text(masked,12,TEXT);label.setGravity(Gravity.CENTER);label.setMaxLines(2);label.setEllipsize(android.text.TextUtils.TruncateAt.END);label.setPadding(dp(10),0,dp(10),0);label.setContentDescription("已保存账号 "+masked);return label;}
  void setPremiumInputsEnabled(EditText account,EditText password,Button action,boolean enabled){account.setEnabled(enabled);account.setClickable(enabled);account.setFocusable(enabled);account.setFocusableInTouchMode(enabled);password.setEnabled(enabled);password.setClickable(enabled);password.setFocusable(enabled);password.setFocusableInTouchMode(enabled);action.setEnabled(enabled);}
  void restorePremiumInputs(EditText account,EditText password,Button action,String error){setPremiumInputsEnabled(account,password,action,true);action.setText("登录");password.setError(error);password.requestFocus();password.post(()->{android.view.inputmethod.InputMethodManager keyboard=(android.view.inputmethod.InputMethodManager)getSystemService(INPUT_METHOD_SERVICE);if(keyboard!=null)keyboard.showSoftInput(password,android.view.inputmethod.InputMethodManager.SHOW_IMPLICIT);});}
  void refreshSettingsFade(String notice){if(notice!=null&&!notice.isEmpty())showNotice(notice,false);pageDirection=0;showSettings();}
  void showPremiumRemoveAccountPicker(List<String> accounts){if(accounts==null||accounts.isEmpty())return;String[] labels=new String[accounts.size()];for(int i=0;i<accounts.size();i++)labels[i]=PremiumCloudClient.maskAccount(accounts.get(i));AlertDialog picker=new AlertDialog.Builder(this).setTitle("选择要移除的账号").setItems(labels,(dialog,index)->confirmRemovePremiumAccount(accounts.get(index))).setNegativeButton("取消",null).create();showRounded(picker);}
  void confirmRemovePremiumAccount(String account){if(account==null||account.isEmpty())return;AlertDialog prompt=new AlertDialog.Builder(this).setTitle("移除账号？").setMessage("将移除 "+PremiumCloudClient.maskAccount(account)+" 的本机加密登录信息，不影响云端账号。").setNegativeButton("取消",null).setPositiveButton("移除",(dialog,which)->io.execute(()->{try{premiumCloud.removeAccount(account);runOnUiThread(()->refreshSettingsFade("账号已移除"));}catch(PremiumCloudClient.CloudException error){showNotice("移除账号失败",true);}})).create();showRounded(prompt);}
  void verifyPremiumAccounts(TextView state,Button action){action.setEnabled(false);state.setText("正在验证全部账号…");io.execute(()->{try{List<PremiumCloudClient.AccountLoginState> results=premiumCloud.queryAllLoginStates(true);int valid=0,premium=0;for(PremiumCloudClient.AccountLoginState result:results)if(result.state.loggedIn){valid++;if(result.state.premium)premium++;}int loggedIn=valid,premiumCount=premium,total=results.size();runOnUiThread(()->{action.setEnabled(true);state.setText("已登录 "+loggedIn+"/"+total+" 个账号"+(loggedIn>0&&loggedIn==premiumCount?" · 优享会员":""));if(loggedIn<total)showNotice("部分账号登录已失效",true);});}catch(PremiumCloudClient.CloudException error){runOnUiThread(()->{action.setEnabled(true);state.setText("账号验证失败");showNotice(premiumMessage(error,"登录状态校验失败"),true);});}});}
  void openPremiumRegistration(){try{startActivity(new Intent(Intent.ACTION_VIEW,Uri.parse("https://www.ilanzou.com/")));}catch(Exception error){showNotice("无法打开蓝奏云优享版注册页",true);}}
