  void enterDownloadSelection(){if(downloadSelectionMode)return;downloadSelectionMode=true;downloadSelectionSummary=text("已选 0",11,TEXT);downloadSelectionAllButton=toolbarTextButton("全选");downloadSelectionAllButton.setOnClickListener(v->toggleSelectAllDownloads());ImageButton directory=iconButton(R.drawable.ic_folder,"打开保存路径"),more=iconButton(R.drawable.ic_open_with,"更多方式打开所选文件"),copyLink=iconButton(R.drawable.ic_copy,"复制所选原链接"),shareFiles=iconButton(R.drawable.ic_share_file,"分享所选本地文件"),location=iconButton(R.drawable.ic_folder_open,"打开所选文件所在路径"),install=iconButton(R.drawable.ic_install,"安装"),pause=iconButton(R.drawable.ic_pause,"暂停或继续所选未完成下载任务"),cancel=iconButton(R.drawable.ic_close,"取消所选未完成下载任务"),deleteRecords=iconButton(R.drawable.ic_delete_record,"删除所选记录"),deleteFiles=iconButton(R.drawable.ic_delete_file,"删除所选本地文件"),shareLinks=iconButton(R.drawable.ic_share,"分享所选原链接"),close=iconButton(R.drawable.ic_close,"退出多选");directory.setOnClickListener(downloadDirectoryClick);more.setOnClickListener(v->openSelectedWithMore());copyLink.setOnClickListener(v->copySelectedDownloadLinks());shareFiles.setOnClickListener(v->shareSelectedDownloadedFiles());location.setOnClickListener(v->openSelectedDownloadLocations());install.setOnClickListener(v->{if(selectedDownloads.size()==1)installEntry(selectedDownloads.iterator().next());else showNotice("请选择一个安装包",false);});pause.setOnClickListener(v->togglePauseSelectedDownloads());cancel.setOnClickListener(v->cancelSelectedDownloads());deleteRecords.setOnClickListener(v->confirmDeleteSelectedRecords());deleteFiles.setOnClickListener(v->confirmDeleteSelectedFiles());shareLinks.setOnClickListener(v->shareSelectedDownloadLinks());close.setOnClickListener(v->exitDownloadSelection());downloadSelectionBar=makeSelectionBar(downloadSelectionSummary,downloadSelectionAllButton,56,48,directory,more,copyLink,shareFiles,location,install,pause,cancel,deleteRecords,deleteFiles,shareLinks,close);showChecks(downloadChecks,true);updateDownloadSelectionSummary();}
  void toggleDownloadSelection(DownloadEntry entry){if(!downloadSelectionMode)enterDownloadSelection();if(toggleChosen(selectedDownloads,entry,downloadChecks))exitDownloadSelection();else updateDownloadSelectionSummary();}
  void toggleSelectAllDownloads(){List<DownloadEntry> visibleEntries=new ArrayList<>(downloadChecks.keySet());if(visibleEntries.isEmpty()){showNotice("当前没有可选择的下载记录",false);return;}if(allChosen(visibleEntries,selectedDownloads)){exitDownloadSelection();return;}selectedDownloads.clear();selectedDownloads.addAll(visibleEntries);syncChecks(selectedDownloads,downloadChecks);updateDownloadSelectionSummary();}
