  void shareSelectedDownloadLinks(){StringBuilder links=new StringBuilder();for(DownloadEntry entry:selectedDownloads)if(!entry.shareUrl.isEmpty()){if(links.length()>0)links.append("\n\n");links.append(entry.shareUrl);if(!entry.password.isEmpty())links.append("\n密码：").append(entry.password);}if(links.length()==0){showNotice("所选记录没有蓝奏链接",false);return;}shareText(links.toString(),"分享蓝奏云链接");}
  void copySelectedDownloadLinks(){StringBuilder links=new StringBuilder();int copied=0;for(DownloadEntry entry:selectedDownloads)if(!entry.shareUrl.isEmpty()){if(links.length()>0)links.append("\n\n");links.append(entry.shareUrl);if(!entry.password.isEmpty())links.append("\n密码：").append(entry.password);copied++;}if(copied==0){showNotice("所选记录没有蓝奏链接",false);return;}((ClipboardManager)getSystemService(CLIPBOARD_SERVICE)).setPrimaryClip(ClipData.newPlainText("蓝奏云原链接",links));showNotice("已复制 "+copied+" 条原链接",false);}
  List<DownloadEntry> selectedReadyDownloads(){List<DownloadEntry> ready=new ArrayList<>();int skipped=0;for(DownloadEntry entry:selectedDownloads){if(entryFileReadable(entry))ready.add(entry);else skipped++;}if(ready.isEmpty()){showNotice("所选记录没有可用的本地文件",false);return ready;}if(skipped>0)showNotice("已跳过 "+skipped+" 个未完成或已缺失文件",false);return ready;}
  void openSelectedWithMore(){if(selectedDownloads.size()!=1){showNotice("请选择一个文件使用更多方式打开",false);return;}openWithMore(selectedDownloads.iterator().next());}
  void shareSelectedDownloadedFiles(){List<DownloadEntry> ready=selectedReadyDownloads();if(ready.isEmpty())return;ArrayList<Uri> uris=new ArrayList<>();boolean allApk=true;for(DownloadEntry entry:ready){uris.add(externalUri(entry));if(!entry.name.toLowerCase(Locale.ROOT).endsWith(".apk"))allApk=false;}String mime=allApk?"application/vnd.android.package-archive":"application/octet-stream";Intent send=new Intent(uris.size()==1?Intent.ACTION_SEND:Intent.ACTION_SEND_MULTIPLE);send.setType(mime);if(uris.size()==1)send.putExtra(Intent.EXTRA_STREAM,uris.get(0));else send.putParcelableArrayListExtra(Intent.EXTRA_STREAM,uris);ClipData clip=ClipData.newRawUri("本地文件",uris.get(0));for(int i=1;i<uris.size();i++)clip.addItem(new ClipData.Item(uris.get(i)));send.setClipData(clip);send.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);try{startActivity(Intent.createChooser(send,"分享所选本地文件"));}catch(Exception error){showNotice("没有可用的分享应用",true);}}
  void openSelectedDownloadLocations(){if(selectedDownloads.isEmpty())return;LinkedHashMap<String,Uri> locations=new LinkedHashMap<>();for(DownloadEntry entry:selectedDownloads){Uri directory=directoryUriForEntry(entry);if(directory!=null)locations.put(directory.toString(),directory);}if(locations.isEmpty()){showNotice("无法识别所选文件所在路径",true);return;}if(locations.size()==1){openDirectoryUri(locations.values().iterator().next());return;}List<Uri> values=new ArrayList<>(locations.values());String[] labels=new String[values.size()];for(int i=0;i<values.size();i++)labels[i]=directoryDisplayPath(values.get(i));AlertDialog prompt=new AlertDialog.Builder(this).setTitle("选择要打开的所在路径").setItems(labels,(dialog,index)->openDirectoryUri(values.get(index))).create();showRounded(prompt);}
  void confirmDeleteSelectedRecords(){List<DownloadEntry> chosen=new ArrayList<>(selectedDownloads);if(chosen.isEmpty())return;AlertDialog prompt=new AlertDialog.Builder(this).setTitle("删除所选记录？").setMessage("将删除 "+chosen.size()+" 条下载记录，本地文件会保留。").setNegativeButton("取消",null).setPositiveButton("删除记录",(d,w)->{downloadEntries.removeAll(chosen);persistDownloadHistory();exitDownloadSelection();renderDownloadFilters();renderDownloads(downloadQuery);showNotice("已删除 "+chosen.size()+" 条记录",false);}).create();showRounded(prompt);}
  void confirmDeleteSelectedFiles(){List<DownloadEntry> chosen=new ArrayList<>(selectedDownloads);if(chosen.isEmpty())return;AlertDialog prompt=new AlertDialog.Builder(this).setTitle("删除所选本地文件？").setMessage("删除成功或文件已不存在时，会同时清理对应下载记录；删除失败的记录会保留。").setNegativeButton("取消",null).setPositiveButton("删除文件",(d,w)->{List<DownloadEntry> removed=new ArrayList<>();int deleted=0,missing=0,failed=0;for(DownloadEntry entry:chosen){int result=deleteDownloadedFileNow(entry);if(result==DELETE_FAILED)failed++;else{removed.add(entry);if(result==DELETE_OK)deleted++;else missing++;}}if(!removed.isEmpty()){downloadEntries.removeAll(removed);persistDownloadHistory();}exitDownloadSelection();renderDownloadFilters();renderDownloads(downloadQuery);showNotice("已删文件 "+deleted+" · 清理缺失 "+missing+(failed>0?" · 失败保留 "+failed:""),failed>0);}).create();showRounded(prompt);}
  Uri entryUri(DownloadEntry entry){if(entry.target==null&&!entry.uriString.isEmpty())entry.target=Uri.parse(entry.uriString);return entry.target;}
  Uri externalUri(DownloadEntry entry){Uri uri=entryUri(entry);if(uri!=null&&"file".equals(uri.getScheme()))return new Uri.Builder().scheme("content").authority(getPackageName()+".downloads").appendPath(new File(uri.getPath()).getName()).build();return uri;}
  boolean entryFileReadable(DownloadEntry entry){if(entry==null||!entry.state.equals("已完成"))return false;Uri uri=entryUri(entry);if(uri==null)return false;if("file".equals(uri.getScheme()))return uri.getPath()!=null&&new File(uri.getPath()).isFile();if(!"content".equals(uri.getScheme()))return false;try(android.os.ParcelFileDescriptor ignored=getContentResolver().openFileDescriptor(uri,"r")){return ignored!=null;}catch(Exception error){return false;}}
  boolean readyFile(DownloadEntry entry){if(!entry.state.equals("已完成")){showNotice("该任务尚未下载完成",false);return false;}if(!entryFileReadable(entry)){showNotice("本地文件已不存在",false);return false;}return true;}
  void installEntry(DownloadEntry entry){
    if(!readyFile(entry))return;if(!entry.name.toLowerCase(Locale.ROOT).endsWith(".apk")){showNotice("该文件不是 APK，无法安装",false);return;}
    if(Build.VERSION.SDK_INT>=26&&!getPackageManager().canRequestPackageInstalls()){confirmUnknownInstallPermission(entry);return;}
    try{Intent install=new Intent(Intent.ACTION_VIEW);install.setDataAndType(externalUri(entry),"application/vnd.android.package-archive");install.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION|Intent.FLAG_ACTIVITY_NEW_TASK);startActivity(install);}catch(Exception error){showNotice("无法启动安装器："+error.getMessage(),true);}
  }
  @android.annotation.SuppressLint("InlinedApi") void confirmUnknownInstallPermission(DownloadEntry entry){AlertDialog prompt=new AlertDialog.Builder(this).setTitle("允许安装此应用？").setMessage("Android 需要先允许 "+"LanzouPlus"+" 安装未知来源应用。授权后会自动继续打开安装器。").setNegativeButton("取消",null).setPositiveButton("前往授权",(d,w)->{try{pendingInstallEntry=entry;startActivity(new Intent(Settings.ACTION_MANAGE_UNKNOWN_APP_SOURCES,Uri.parse("package:"+getPackageName())));}catch(Exception error){pendingInstallEntry=null;showNotice("无法打开安装权限设置",true);}}).create();showRounded(prompt);}
  void downloadMenu(DownloadEntry entry){String[] actions={"跳转 Download 目录","安装","删除记录","删除文件","分享文件","分享蓝奏云链接","更多方式"};AlertDialog menu=new AlertDialog.Builder(this).setTitle(entry.name).setItems(actions,(dialog,index)->{switch(index){case 0:openDownloadDirectory();break;case 1:installEntry(entry);break;case 2:removeDownloadRecord(entry);break;case 3:confirmDeleteFile(entry);break;case 4:shareDownloadedFile(entry);break;case 5:shareDownloadLink(entry);break;case 6:openWithMore(entry);break;default:break;}}).create();showRounded(menu);}
  String downloadMimeType(DownloadEntry entry){Uri uri=entryUri(entry);if(uri!=null&&"content".equals(uri.getScheme()))try{String value=getContentResolver().getType(uri);if(value!=null&&!value.trim().isEmpty())return value;}catch(Exception ignored){}return entry.name.toLowerCase(Locale.ROOT).endsWith(".apk")?"application/vnd.android.package-archive":"application/octet-stream";}
  void openWithMore(DownloadEntry entry){if(!readyFile(entry))return;try{Uri uri=externalUri(entry);Intent view=new Intent(Intent.ACTION_VIEW);view.setDataAndType(uri,downloadMimeType(entry));view.setClipData(ClipData.newRawUri(entry.name,uri));view.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);startActivity(Intent.createChooser(view,"更多方式打开"));}catch(Exception error){showNotice("没有更多可用方式",true);}}
  Uri selectedDownloadTree(){String raw=getSharedPreferences("download_destination",MODE_PRIVATE).getString("tree","");try{return raw==null||raw.isEmpty()?null:Uri.parse(raw);}catch(Exception ignored){return null;}}
  Uri validatedSelectedDownloadTree(){Uri tree=selectedDownloadTree();if(tree==null)return null;List<android.content.UriPermission> persistedUriPermissions=getContentResolver().getPersistedUriPermissions();for(android.content.UriPermission permission:persistedUriPermissions)if(tree.equals(permission.getUri())&&permission.isReadPermission()&&permission.isWritePermission())return tree;getSharedPreferences("download_destination",MODE_PRIVATE).edit().remove("tree").apply();showNotice("保存路径权限已失效，请长按保存路径重新选择",true);return null;}
  Uri defaultDownloadDocument(){return Uri.parse("content://com.android.externalstorage.documents/document/primary%3ADownload");}
  Uri directoryDocumentUri(Uri target){if(target==null)return defaultDownloadDocument();try{String treeId=android.provider.DocumentsContract.getTreeDocumentId(target);return android.provider.DocumentsContract.buildDocumentUriUsingTree(target,treeId);}catch(Exception ignored){return target;}}
  Uri currentDownloadParentUri(){Uri tree=validatedSelectedDownloadTree();return tree==null?defaultDownloadDocument():directoryDocumentUri(tree);}
  Uri directoryUriForEntry(DownloadEntry entry){if(entry!=null&&!entry.parentUriString.isEmpty())try{return directoryDocumentUri(Uri.parse(entry.parentUriString));}catch(Exception ignored){}Uri uri=entryUri(entry);if(uri==null)return null;try{String treeId=android.provider.DocumentsContract.getTreeDocumentId(uri);return android.provider.DocumentsContract.buildDocumentUriUsingTree(uri,treeId);}catch(Exception ignored){}try{String documentId=android.provider.DocumentsContract.getDocumentId(uri);int slash=documentId.lastIndexOf('/');if(slash>0){String parent=documentId.substring(0,slash);return Uri.parse("content://"+uri.getAuthority()+"/document/"+Uri.encode(parent));}}catch(Exception ignored){}if("file".equals(uri.getScheme())&&uri.getPath()!=null){File parent=new File(uri.getPath()).getParentFile();try{String root=Environment.getExternalStorageDirectory().getCanonicalPath(),path=parent==null?"":parent.getCanonicalPath();if(path.equals(root)||path.startsWith(root+File.separator)){String relative=path.length()==root.length()?"":path.substring(root.length()+1).replace(File.separatorChar,'/');return Uri.parse("content://com.android.externalstorage.documents/document/"+Uri.encode("primary:"+relative));}}catch(Exception ignored){}}return defaultDownloadDocument();}
  String directoryDisplayPath(Uri target){if(target==null)return Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS).getAbsolutePath();String id="";try{id=android.provider.DocumentsContract.getTreeDocumentId(target);}catch(Exception ignored){try{id=android.provider.DocumentsContract.getDocumentId(target);}catch(Exception ignoredAgain){}}if(id.isEmpty())return target.toString();if(id.startsWith("raw:"))return id.substring(4);int split=id.indexOf(':');String volume=split<0?id:id.substring(0,split),path=split<0?"":id.substring(split+1);String root=volume.equalsIgnoreCase("primary")?Environment.getExternalStorageDirectory().getAbsolutePath():volume.equalsIgnoreCase("home")?new File(Environment.getExternalStorageDirectory(),"Documents").getAbsolutePath():"/storage/"+volume;return path.isEmpty()?root:new File(root,path).getPath();}
  String downloadDisplayPath(){Uri tree=validatedSelectedDownloadTree();return tree==null?Environment.getExternalStoragePublicDirectory(Environment.DIRECTORY_DOWNLOADS).getAbsolutePath():directoryDisplayPath(tree);}
  void chooseDownloadDirectory(){try{Intent picker=new Intent(Intent.ACTION_OPEN_DOCUMENT_TREE);Uri initial=validatedSelectedDownloadTree();picker.putExtra("android.provider.extra.INITIAL_URI",initial==null?defaultDownloadDocument():initial);picker.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION|Intent.FLAG_GRANT_WRITE_URI_PERMISSION|Intent.FLAG_GRANT_PERSISTABLE_URI_PERMISSION|Intent.FLAG_GRANT_PREFIX_URI_PERMISSION);startActivityForResult(picker,PICK_DOWNLOAD_TREE);}catch(Exception error){showNotice("系统没有可用的目录选择器",true);}}
  void openDirectoryUri(Uri target){Uri original=target==null?defaultDownloadDocument():target,directory=directoryDocumentUri(original);Intent view=new Intent(Intent.ACTION_VIEW);view.setDataAndType(directory,android.provider.DocumentsContract.Document.MIME_TYPE_DIR);ClipData paths=ClipData.newRawUri("保存路径",original);if(!original.equals(directory))paths.addItem(new ClipData.Item(directory));view.setClipData(paths);view.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION|Intent.FLAG_GRANT_PREFIX_URI_PERMISSION);Intent picker=new Intent(Intent.ACTION_OPEN_DOCUMENT_TREE);picker.putExtra("android.provider.extra.INITIAL_URI",directory);picker.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION|Intent.FLAG_GRANT_PREFIX_URI_PERMISSION);ArrayList<Intent> alternatives=new ArrayList<>();alternatives.add(view);if(defaultDownloadDocument().equals(directory))alternatives.add(new Intent(android.app.DownloadManager.ACTION_VIEW_DOWNLOADS));Intent chooser=Intent.createChooser(picker,"选择文件管理器");chooser.putExtra(Intent.EXTRA_INITIAL_INTENTS,alternatives.toArray(new Intent[0]));try{startActivity(chooser);}catch(Exception ignored){showNotice("系统没有可用的文件管理器",true);}}
  void openDownloadDirectory(){Uri tree=validatedSelectedDownloadTree();openDirectoryUri(tree==null?defaultDownloadDocument():tree);}
  void removeDownloadRecord(DownloadEntry entry){downloadEntries.remove(entry);persistDownloadHistory();if(downloadsPage){renderDownloadFilters();renderDownloads(downloadQuery);}showNotice("已删除下载记录，文件保留",false);}
  void confirmDeleteFile(DownloadEntry entry){AlertDialog prompt=new AlertDialog.Builder(this).setTitle("删除本地文件？").setMessage(entry.name+"\n\n删除成功或文件已不存在时，会同时清理这条下载记录。").setNegativeButton("取消",null).setPositiveButton("删除",(dialog,which)->deleteDownloadedFile(entry)).create();showRounded(prompt);}
  int deleteDownloadedFileNow(DownloadEntry entry){Uri uri=entryUri(entry);if(uri==null)return DELETE_MISSING;try{if("file".equals(uri.getScheme())){String path=uri.getPath();if(path==null)return DELETE_MISSING;File file=new File(path);if(!file.exists())return DELETE_MISSING;if(!file.delete())return DELETE_FAILED;}else if("content".equals(uri.getScheme())){if(getContentResolver().delete(uri,null,null)<=0)try(android.os.ParcelFileDescriptor remaining=getContentResolver().openFileDescriptor(uri,"r")){return remaining==null?DELETE_MISSING:DELETE_FAILED;}catch(FileNotFoundException missing){return DELETE_MISSING;}}else return DELETE_FAILED;entry.target=null;entry.uriString="";return DELETE_OK;}catch(FileNotFoundException missing){return DELETE_MISSING;}catch(Exception error){return DELETE_FAILED;}}
  void deleteDownloadedFile(DownloadEntry entry){int result=deleteDownloadedFileNow(entry);if(result==DELETE_FAILED){showNotice("文件删除失败，下载记录已保留",true);return;}downloadEntries.remove(entry);persistDownloadHistory();if(downloadsPage){renderDownloadFilters();renderDownloads(downloadQuery);}showNotice(result==DELETE_OK?"本地文件与下载记录已删除":"文件已不存在，下载记录已清理",false);}
  void shareDownloadedFile(DownloadEntry entry){if(!readyFile(entry))return;try{Uri uri=externalUri(entry);Intent send=new Intent(Intent.ACTION_SEND);send.setType(downloadMimeType(entry));send.putExtra(Intent.EXTRA_STREAM,uri);send.setClipData(ClipData.newRawUri(entry.name,uri));send.addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION);startActivity(Intent.createChooser(send,"分享 "+entry.name));}catch(Exception error){showNotice("无法分享本地文件",true);}}
  void shareDownloadLink(DownloadEntry entry){if(entry.shareUrl.isEmpty()){showNotice("该记录没有蓝奏云链接",false);return;}shareText(entry.shareUrl+(entry.password.isEmpty()?"":"\n密码："+entry.password),"分享蓝奏云链接");}

