  int webUrlEnd(CharSequence text,int start,int end){while(end>start&&".,;:!?)]}".indexOf(text.charAt(end-1))>=0)end--;return end;}
  void selectableLinks(TextView view){CharSequence raw=view.getText();android.text.SpannableString linked=new android.text.SpannableString(raw);java.util.regex.Matcher matches=WEB_URL_CJK.matcher(raw);while(matches.find()){int start=matches.start(),end=webUrlEnd(raw,start,matches.end());if(end<=start)continue;String url=raw.subSequence(start,end).toString();linked.setSpan(new android.text.style.ClickableSpan(){@Override public void onClick(View widget){openRecognizedLink(url,"");}@Override public void updateDrawState(android.text.TextPaint paint){paint.setColor(PRIMARY);paint.setUnderlineText(true);}},start,end,android.text.Spanned.SPAN_EXCLUSIVE_EXCLUSIVE);}view.setText(linked);view.setTextIsSelectable(true);view.setMovementMethod(LinkMovementMethod.getInstance());view.setLinksClickable(true);}
  void setSelectableLinks(TextView view,String value){view.setText(value);selectableLinks(view);}
  String normalizedWebUrl(String raw){String value=raw==null?"":raw.trim();int end=webUrlEnd(value,0,value.length());value=value.substring(0,end);if(value.isEmpty())return"";if(!value.matches("(?i)^[a-z][a-z0-9+.-]*://.*"))value="https://"+value;return value;}
  boolean isProductReleaseHost(String host){return host!=null&&host.endsWith(".nkbr.cc")&&host.startsWith("lanzou");}
  boolean isRealLanzouHost(String host){if(host==null)return false;host=host.toLowerCase(Locale.ROOT);while(host.endsWith("."))host=host.substring(0,host.length()-1);if(isProductReleaseHost(host))return false;return LANZOU_CLOUD_HOST.matcher(host).matches();}
  boolean isLanzouUrl(String value){String normalized=normalizedWebUrl(value);if(normalized.isEmpty())return false;try{return isRealLanzouHost(Uri.parse(normalized).getHost());}catch(Exception ignored){return false;}}
  void openRecognizedLink(String raw,String password){String normalized=normalizedWebUrl(raw);if(normalized.isEmpty()){showNotice("链接为空",false);return;}if(isLanzouUrl(normalized)){if(directLanzouListOpen)openLanzouList(normalized,password);else showLanzouOpenDialog(normalized,password);return;}openInBrowser(normalized,password);}
  void showLanzouOpenDialog(String url,String password){AlertDialog prompt=new AlertDialog.Builder(this).setTitle("打开蓝奏云链接").setMessage(url).setNegativeButton("浏览器打开",(dialog,which)->openInBrowser(url,password)).setPositiveButton("列表解析打开",(dialog,which)->openLanzouList(url,password)).create();showRounded(prompt);}
  void openInBrowser(String url,String password){try{Uri uri=Uri.parse(normalizedWebUrl(url));String scheme=uri.getScheme();if(uri.getHost()==null||scheme==null||!(scheme.equalsIgnoreCase("http")||scheme.equalsIgnoreCase("https")||scheme.equalsIgnoreCase("ftp")))throw new IllegalArgumentException();if(password!=null&&!password.isEmpty()){((ClipboardManager)getSystemService(CLIPBOARD_SERVICE)).setPrimaryClip(ClipData.newPlainText("蓝奏云密码",password));showNotice("密码已复制",false);}startActivity(new Intent(Intent.ACTION_VIEW,uri));}catch(Exception error){showNotice("无法打开链接",true);}}
  void openLanzouList(String url,String rawPassword){String normalized=normalizedWebUrl(url),password=rawPassword==null?"":rawPassword;Models.Source directory=new Models.Source();directory.title="蓝奏云链接";directory.url=normalized;directory.password=password;if(normalized.contains("#lanzou-folder=")){openSourcePage(directory);return;}Models.Source page=new Models.Source();page.id="link:"+Integer.toHexString((normalized+'\n'+password).hashCode());page.kind=Models.SOURCE_COMPOSITE;page.title="蓝奏云链接";page.url=normalized;page.password=password;page.description="正在后台解析分享内容";openSourcePage(page);int request=navigationSession;io.execute(()->{try{Models.SourceMember member=core.probeSingleSource(normalized,password);member.id="item";member.parentId="";member.lightweight=member.metadataLoaded=member.iconLoaded=member.detailsLoaded=true;Models.Source source=new Models.Source();source.id=page.id;source.kind=Models.SOURCE_COMPOSITE;source.title=member.title.isEmpty()?"蓝奏云分享":member.title;source.url=normalized;source.password=password;source.avatarUrl=member.iconUrl;source.description=member.description;source.members.add(member);runOnUiThread(()->{if(request!=navigationSession||isFinishing())return;if(content==null){openSourcePage(source);return;}applyResolvedLanzouList(request,normalized,source);});}catch(Exception notSingle){runOnUiThread(()->applyResolvedLanzouDirectory(request,normalized,directory));}});}
  void applyResolvedLanzouList(int request,String normalized,Models.Source source){if(request!=navigationSession||activeSource==null||!normalized.equals(activeSource.url)||content==null)return;FolderPageState state=currentFolderState();if(state==null)return;copySource(source,state.source);activeFolderState=state;activeSource=state.source;renderFolder(core.compositeSnapshot(activeSource));}
  void applyResolvedLanzouDirectory(int request,String normalized,Models.Source directory){if(request!=navigationSession||activeSource==null||!normalized.equals(activeSource.url)||content==null)return;FolderPageState state=currentFolderState();if(state==null)return;copySource(directory,state.source);activeFolderState=state;activeSource=state.source;openFolder(activeSource,true);}

