  LinearLayout toastPanel(){LinearLayout panel=new LinearLayout(this);panel.setOrientation(LinearLayout.VERTICAL);panel.setPadding(dp(10),dp(8),dp(10),dp(8));panel.setBackground(solidShape(SURFACE,16));panel.setElevation(dp(6));return panel;}
  void addToastPanel(LinearLayout panel,int height){toastScroll.setVisibility(View.VISIBLE);LinearLayout.LayoutParams lp=new LinearLayout.LayoutParams(-1,dp(height));lp.setMargins(0,0,0,dp(5));toastLayer.addView(panel,lp);swipePanel(panel,()->dismissPanel(panel,null),null);toastScroll.post(()->{if(motionEnabled())toastScroll.smoothScrollTo(0,toastLayer.getHeight());else toastScroll.scrollTo(0,toastLayer.getHeight());});if(motionEnabled()){panel.setAlpha(0f);panel.setTranslationX(-dp(260));panel.animate().alpha(1f).translationX(0).setDuration(210).start();}else{panel.setAlpha(1f);panel.setTranslationX(0);}}
