  BatchToastState createBatchParsingToast(List<Models.Item> items,List<DownloadEntry> entries){BatchToastState state=new BatchToastState();state.total=items.size();state.remaining.set(state.total);downloadToastEntries.addAll(entries);syncDownloadToastPresentation();return state;}
  void finishBatchParsing(BatchToastState batch){if(batch==null)return;batch.remaining.updateAndGet(value->Math.max(0,value-1));runOnUiThread(()->{if(mergedDownloadToast!=null)updateMergedDownloadToast(visibleDownloadToastEntries());});}
  void updateDownloadUi(DownloadEntry entry){
    persistDownloadHistory(entry);boolean post=false;synchronized(dirtyDownloadUi){dirtyDownloadUi.add(entry);if(!downloadUiFramePosted){downloadUiFramePosted=true;post=true;}}if(post)ui.postDelayed(this::drainDownloadUi,16);
  }
  void drainDownloadUi(){List<DownloadEntry> changed;synchronized(dirtyDownloadUi){changed=new ArrayList<>(dirtyDownloadUi);dirtyDownloadUi.clear();downloadUiFramePosted=false;}refreshDownloadGlobalControl();boolean rebuild=false,toastStructureChanged=false;List<DownloadEntry> toastContentChanged=new ArrayList<>();for(DownloadEntry entry:changed){boolean stateChanged=!entry.state.equals(entry.uiState);entry.uiState=entry.state;boolean terminal=entry.state.equals(DOWNLOAD_COMPLETED)||entry.state.equals(DOWNLOAD_FAILED)||entry.state.equals(DOWNLOAD_CANCELLED),parsing=entry.state.equals(DOWNLOAD_RESOLVING);if(downloadsPage){boolean shown=downloadLabels.containsKey(entry),matches=downloadMatchesCurrentView(entry);if(shown!=matches)rebuild=true;else if(shown){TextView label=downloadLabels.get(entry);if(label!=null&&label.getParent()!=null)label.setText(downloadMetrics(entry));ProgressBar bar=downloadBars.get(entry);if(bar!=null&&bar.getParent()!=null){bar.setIndeterminate(parsing);if(!parsing){bar.setIndeterminate(false);bar.setProgress(entry.percent);}}if(stateChanged){LinearLayout actions=downloadActions.get(entry);if(actions!=null&&actions.getParent()!=null)bindDownloadActions(entry,actions);View row=downloadRows.get(entry);if(row!=null&&row.getParent()!=null)bindDownloadRowDescription(entry,row);}}}boolean show=!parsing||!entry.suppressParseToast;if(show&&!entry.toastDismissed){if(downloadToastEntries.add(entry))toastStructureChanged=true;toastContentChanged.add(entry);if(terminal&&!entry.dismissScheduled){entry.dismissScheduled=true;int generation=entry.controlGeneration;ui.postDelayed(()->{if(generation!=entry.controlGeneration||!entry.dismissScheduled)return;entry.toastDismissed=true;downloadToastEntries.remove(entry);detachDownloadToast(entry);syncDownloadToastPresentation();},entry.state.equals(DOWNLOAD_COMPLETED)?5000:3200);}}}if(rebuild)renderDownloads(downloadQuery);if(toastStructureChanged)syncDownloadToastPresentation();else if(mergedDownloadToast!=null)updateMergedDownloadToast(visibleDownloadToastEntries());else for(DownloadEntry entry:toastContentChanged){LinearLayout panel=taskToasts.get(entry);if(panel!=null&&panel.getParent()==toastLayer)updateDownloadToast(entry,panel);else if(downloadToastEntries.contains(entry)){syncDownloadToastPresentation();break;}}}
  void showNotice(String message,boolean longLived){runOnUiThread(()->{TextView notice=text(message,12,TEXT);notice.setPadding(dp(4),0,dp(4),0);LinearLayout holder=toastPanel();holder.addView(notice,new LinearLayout.LayoutParams(-1,-1));addToastPanel(holder,48);notice.postDelayed(()->{if(holder.getParent()==toastLayer)dismissPanel(holder,null);},longLived?5000:2500);});}
  void saveDialog(String url){String target=url==null?"":url.trim();if(target.isEmpty()){showNotice("当前分享没有可用的保存入口",false);return;}Runnable confirm=()->showPremiumSaveConfirm(target);if(premiumCloud.hasStoredLogin())confirm.run();else showPremiumLoginDialog(confirm);}
  void showPremiumLoginDialog(Runnable afterLogin){
    LinearLayout panel=new LinearLayout(this);panel.setOrientation(LinearLayout.VERTICAL);panel.setPadding(dp(22),dp(6),dp(22),0);
    EditText account=new EditText(this);account.setSingleLine();account.setSaveEnabled(false);account.setTextColor(TEXT);account.setHintTextColor(MUTED);account.setHint("账号");account.setInputType(android.text.InputType.TYPE_CLASS_TEXT);
    EditText password=new EditText(this);password.setSingleLine();password.setSaveEnabled(false);password.setTextColor(TEXT);password.setHintTextColor(MUTED);password.setHint("密码");password.setInputType(android.text.InputType.TYPE_CLASS_TEXT|android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD);
    TextView note=text("登录信息仅加密保存在本机，用于判断登录状态与保存分享。",11,MUTED);note.setPadding(0,dp(5),0,0);panel.addView(account,new LinearLayout.LayoutParams(-1,dp(54)));panel.addView(password,new LinearLayout.LayoutParams(-1,dp(54)));panel.addView(note,new LinearLayout.LayoutParams(-1,-2));
    AlertDialog prompt=new AlertDialog.Builder(this).setTitle("登录蓝奏云优享版").setView(panel).setNegativeButton("取消",null).setNeutralButton("注册",(dialog,which)->openPremiumRegistration()).setPositiveButton("登录",null).create();
    prompt.setOnDismissListener(ignored->{account.setText("");password.setText("");});
    prompt.setOnShowListener(ignored->{
      Button login=prompt.getButton(AlertDialog.BUTTON_POSITIVE);
      login.setOnClickListener(v->{
        String name=account.getText().toString().trim(),secret=password.getText().toString();
        if(name.isEmpty()){account.setError("请输入账号");account.requestFocus();return;}
        if(secret.isEmpty()){password.setError("请输入密码");password.requestFocus();return;}
        setPremiumInputsEnabled(account,password,login,false);login.setText("登录中…");
        io.execute(()->{try{
          PremiumCloudClient.LoginState state=premiumCloud.loginAndRemember(name,secret);
          runOnUiThread(()->{if(isFinishing()||isDestroyed())return;if(!state.loggedIn){restorePremiumInputs(account,password,login,"账号或密码错误");return;}prompt.dismiss();if(afterLogin!=null)afterLogin.run();else showNotice("蓝奏云优享版已登录",false);});
        }catch(PremiumCloudClient.CloudException error){runOnUiThread(()->{if(isFinishing()||isDestroyed())return;restorePremiumInputs(account,password,login,"账号或密码错误，请重新输入");});}});
      });
    });
    showRounded(prompt);
  }
  String premiumMessage(PremiumCloudClient.CloudException error,String fallback){String message=error==null?"":error.getMessage();return message==null||message.trim().isEmpty()?fallback:message.trim();}
  boolean requiresPremiumLogin(PremiumCloudClient.CloudException error){return error.needsCredentials()||error.sessionExpired()||error.code()==401||error.code()==403;}
  void showPremiumSaveConfirm(String url){List<String> accounts;try{accounts=premiumCloud.accountNames();}catch(PremiumCloudClient.CloudException error){showNotice("无法读取账号列表",true);return;}if(accounts.isEmpty()){showPremiumLoginDialog(()->showPremiumSaveConfirm(url));return;}showPremiumAccountMultiPicker("保存到蓝奏云优享版？",accounts,selected->performPremiumSave(url,selected));}
  void showPremiumAccountMultiPicker(String title,List<String> accounts,java.util.function.Consumer<List<String>> accepted){String[] labels=new String[accounts.size()];boolean[] checked=new boolean[accounts.size()];for(int i=0;i<accounts.size();i++)labels[i]=PremiumCloudClient.maskAccount(accounts.get(i));AlertDialog picker=new AlertDialog.Builder(this).setTitle(title).setMultiChoiceItems(labels,checked,(dialog,index,value)->checked[index]=value).setNegativeButton("取消",null).setNeutralButton("全选",null).setPositiveButton("保存",null).create();picker.setOnShowListener(ignored->{Button all=picker.getButton(AlertDialog.BUTTON_NEUTRAL),save=picker.getButton(AlertDialog.BUTTON_POSITIVE);all.setText("全选");all.setOnClickListener(v->{for(int i=0;i<checked.length;i++){checked[i]=true;picker.getListView().setItemChecked(i,true);}});save.setOnClickListener(v->{List<String> selected=new ArrayList<>();for(int i=0;i<checked.length;i++)if(checked[i])selected.add(accounts.get(i));if(selected.isEmpty()){showNotice("请至少选择一个账号",false);return;}picker.dismiss();accepted.accept(selected);});});showRounded(picker);}
  String premiumSaveFailureReason(PremiumCloudClient.AccountSaveResult result){String message=result.message==null?"":result.message.trim();if(!message.isEmpty())return message;if(result.errorCode==401||result.errorCode==403||result.errorCode==-2)return"登录状态已失效，请重新登录";return result.errorCode==0?"蓝奏云未返回成功状态":"保存失败（错误 "+result.errorCode+"）";}
  void appendPremiumSaveResults(PremiumSaveReport report,Models.Source source,String url,List<PremiumCloudClient.AccountSaveResult> results){for(PremiumCloudClient.AccountSaveResult result:results)report.attempts.add(new PremiumSaveAttempt(source,url,result.accountName,result.saved,result.saved?"保存成功":premiumSaveFailureReason(result)));}
  void appendPremiumSaveFailure(PremiumSaveReport report,Models.Source source,String url,List<String> accounts,String reason){for(String account:accounts)report.attempts.add(new PremiumSaveAttempt(source,url,account,false,reason));}
  void showPremiumSaveReport(PremiumSaveReport report){int success=0;for(PremiumSaveAttempt attempt:report.attempts)if(attempt.saved)success++;int failure=report.attempts.size()-success;LinearLayout rows=new LinearLayout(this);rows.setOrientation(LinearLayout.VERTICAL);TextView summary=text("成功 "+success+" · 失败 "+failure+(report.requestedSources>1?"\n完整保存 "+report.completeSources+" / "+report.requestedSources+" 个源":""),15,success>0&&failure==0?PRIMARY:TEXT);summary.setPadding(dp(6),dp(4),dp(6),dp(10));rows.addView(summary,new LinearLayout.LayoutParams(-1,-2));for(PremiumSaveAttempt attempt:report.attempts){String source=attempt.source==null?"当前分享":attempt.source.title;TextView row=text((attempt.saved?"保存成功":"保存失败")+" · "+PremiumCloudClient.maskAccount(attempt.account)+"\n"+source+(attempt.reason.isEmpty()?"":" · "+attempt.reason),12,attempt.saved?PRIMARY:TEXT);row.setPadding(dp(10),dp(9),dp(10),dp(9));row.setBackground(filterRipple(new ColorDrawable(Color.TRANSPARENT)));String target=attempt.source!=null&&!attempt.source.url.isEmpty()?attempt.source.url:attempt.url,password=attempt.source==null?"":attempt.source.password;if(!target.isEmpty()){row.setClickable(true);row.setFocusable(true);row.setContentDescription("打开 "+source+" 查看保存目标");row.setOnClickListener(v->openRecognizedLink(target,password));}rows.addView(row,new LinearLayout.LayoutParams(-1,-2));}ScrollView scroll=new ScrollView(this);scroll.setFillViewport(false);scroll.addView(rows,new ScrollView.LayoutParams(-1,-2));LinearLayout panel=new LinearLayout(this);panel.setPadding(dp(16),dp(4),dp(16),0);panel.addView(scroll,new LinearLayout.LayoutParams(-1,Math.min(dp(390),Math.max(dp(120),dp(78+report.attempts.size()*58)))));AlertDialog dialog=new AlertDialog.Builder(this).setTitle("保存结果").setView(panel).setNegativeButton("关闭",null).setPositiveButton("打开优享版",(d,w)->openPremiumRegistration()).create();showRounded(dialog);}
  void performPremiumSave(String url,List<String> accounts){showNotice(accounts.size()>1?"正在保存到 "+accounts.size()+" 个账号":"正在保存到蓝奏云优享版",true);io.execute(()->{PremiumSaveReport report=new PremiumSaveReport();report.requestedSources=1;try{List<PremiumCloudClient.AccountSaveResult> results=premiumCloud.saveFromShareAccounts(url,accounts,true);appendPremiumSaveResults(report,null,url,results);boolean complete=results.size()==accounts.size();for(PremiumCloudClient.AccountSaveResult result:results)complete&=result.saved;if(complete)report.completeSources=1;}catch(PremiumCloudClient.CloudException error){appendPremiumSaveFailure(report,null,url,accounts,premiumMessage(error,"保存失败，请稍后重试"));}runOnUiThread(()->showPremiumSaveReport(report));});}
  void confirmSaveSelectedSources(){List<Models.Source> selected=selectedSources(),chosen=new ArrayList<>();for(Models.Source source:selected)if(!compositeSource(source))chosen.add(source);if(chosen.isEmpty()){showNotice("自建合集没有可保存的单一网盘入口",false);return;}if(chosen.size()<selected.size())showNotice("已跳过 "+(selected.size()-chosen.size())+" 个自建合集",false);Runnable confirm=()->showPremiumSourceConfirm(chosen);if(premiumCloud.hasStoredLogin())confirm.run();else showPremiumLoginDialog(confirm);}
  void showPremiumSourceConfirm(List<Models.Source> chosen){List<String> accounts;try{accounts=premiumCloud.accountNames();}catch(PremiumCloudClient.CloudException error){showNotice("无法读取账号列表",true);return;}if(accounts.isEmpty()){showPremiumLoginDialog(()->showPremiumSourceConfirm(chosen));return;}showPremiumAccountMultiPicker("保存所选 "+chosen.size()+" 个源？",accounts,selected->performPremiumSourceBatch(chosen,selected));}
  void performPremiumSourceBatch(List<Models.Source> chosen,List<String> accounts){showNotice("正在获取并保存 "+chosen.size()+" 个源到 "+accounts.size()+" 个账号",true);io.execute(()->{PremiumSaveReport report=new PremiumSaveReport();report.requestedSources=chosen.size();for(Models.Source source:chosen){if(compositeSource(source))continue;try{Models.Folder folder=core.browseSource(source,true);String saveUrl=folder.saveUrl==null?"":folder.saveUrl.trim();if(saveUrl.isEmpty()){appendPremiumSaveFailure(report,source,source.url,accounts,"当前源没有可用的保存入口");continue;}List<PremiumCloudClient.AccountSaveResult> results=premiumCloud.saveFromShareAccounts(saveUrl,accounts,true);appendPremiumSaveResults(report,source,saveUrl,results);boolean complete=results.size()==accounts.size();for(PremiumCloudClient.AccountSaveResult result:results)complete&=result.saved;if(complete)report.completeSources++;}catch(PremiumCloudClient.CloudException error){appendPremiumSaveFailure(report,source,source.url,accounts,premiumMessage(error,"保存失败，请稍后重试"));}catch(Exception error){appendPremiumSaveFailure(report,source,source.url,accounts,friendlyError(error));}}runOnUiThread(()->{if(sourceSelectionMode)exitSourceSelection();showPremiumSaveReport(report);});});}
  void postFolderIconPrefetch(List<Models.Item> items,int start,int limit){if(start>=items.size()||limit<=0)return;int session=navigationSession;List<Models.Item> snapshot=new ArrayList<>(items);ui.postDelayed(()->{if(session!=navigationSession||pageKind!=3)return;for(int i=start;i<Math.min(start+limit,snapshot.size());i++)requestImage(snapshot.get(i).iconUrl,null);},180);}
  void loadImage(String url,ImageView view){if(restoringFolderState){loadCachedFolderImage(url,view);return;}requestImage(url,view);}
  void loadCachedFolderImage(String url,ImageView view){if(view==null||url==null||url.isEmpty())return;view.setTag(url);Bitmap bitmap=activeFolderState==null?null:activeFolderState.pinnedIcons.get(url);if(bitmap==null)bitmap=imageCache.get(url);if(bitmap!=null&&url.equals(view.getTag())){view.setImageBitmap(bitmap);return;}synchronized(imageLock){List<java.lang.ref.WeakReference<ImageView>> waiters=imageWaiters.get(url);if(waiters!=null)waiters.add(new java.lang.ref.WeakReference<>(view));}}
  void requestImage(String url,ImageView view){if(url==null||url.isEmpty())return;if(view!=null)view.setTag(url);Bitmap cached=imageCache.get(url);if(cached!=null){if(view!=null&&url.equals(view.getTag()))view.setImageBitmap(cached);return;}boolean start=false;synchronized(imageLock){List<java.lang.ref.WeakReference<ImageView>> waiters=imageWaiters.get(url);if(waiters==null){waiters=new ArrayList<>();imageWaiters.put(url,waiters);start=true;}if(view!=null)waiters.add(new java.lang.ref.WeakReference<>(view));}if(!start)return;imageIo.execute(()->{HttpURLConnection c=null;Bitmap bitmap=null;try{c=(HttpURLConnection)new URL(url).openConnection();c.setConnectTimeout(8000);c.setReadTimeout(8000);c.setRequestProperty("User-Agent","Mozilla/5.0 (Linux; Android 15; Mobile) AppleWebKit/537.36 Chrome/138 Mobile Safari/537.36");c.setRequestProperty("Referer","https://www.lanzouw.com/");try(InputStream in=c.getInputStream()){bitmap=BitmapFactory.decodeStream(in);if(bitmap!=null)imageCache.put(url,bitmap);}}catch(Exception ignored){}finally{if(c!=null)c.disconnect();}List<java.lang.ref.WeakReference<ImageView>> targets;synchronized(imageLock){targets=imageWaiters.remove(url);}if(bitmap!=null&&targets!=null)queueImageDelivery(url,bitmap,targets);});}
  void queueImageDelivery(String url,Bitmap bitmap,List<java.lang.ref.WeakReference<ImageView>> targets){boolean post=false;synchronized(imageLock){imageDeliveries.addLast(new ImageDelivery(url,bitmap,targets));if(!imageDeliveryPosted){imageDeliveryPosted=true;post=true;}}if(post)ui.post(this::drainImageDeliveries);}
  void drainImageDeliveries(){List<ImageDelivery> ready=new ArrayList<>();boolean more;synchronized(imageLock){while(ready.size()<IMAGE_UI_CHUNK&&!imageDeliveries.isEmpty())ready.add(imageDeliveries.removeFirst());more=!imageDeliveries.isEmpty();if(!more)imageDeliveryPosted=false;}for(ImageDelivery delivery:ready)for(java.lang.ref.WeakReference<ImageView> reference:delivery.targets){ImageView target=reference.get();if(target!=null&&delivery.url.equals(target.getTag()))target.setImageBitmap(delivery.bitmap);}if(more)ui.postDelayed(this::drainImageDeliveries,16);}
  void error(Exception e){runOnUiThread(()->{if(progress!=null)progress.setVisibility(View.GONE);showNotice(friendlyError(e),true);});}
